#[php_class]
#[php(name = "Liter\\Llm\\LiterLlmApi")]
pub struct LiterLlmApi;

#[php_impl]
impl LiterLlmApi {
    /**
     * Create a new LLM client with simple scalar configuration.
     *
     * This is the primary binding entry-point. All parameters except `api_key`
     * are optional — omitting them uses the same defaults as
     * [`ClientConfigBuilder`].
     * @throws LiterLlmException Returns [`LiterLlmError`] if the underlying HTTP client cannot be
     * constructed, or if the resolved provider configuration is invalid.
     */
    pub fn create_client(
        apiKey: String,
        baseUrl: Option<String>,
        timeoutSecs: Option<i64>,
        maxRetries: Option<u32>,
        modelHint: Option<String>,
    ) -> PhpResult<DefaultClient> {
        let result = liter_llm::create_client(apiKey, baseUrl, timeoutSecs.map(|v| v as u64), maxRetries, modelHint)
            .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
        Ok(DefaultClient {
            inner: Arc::new(result),
        })
    }

    /**
     * Create a new LLM client from a JSON string.
     *
     * The JSON object accepts the same fields as `liter-llm.toml` (snake_case).
     * @throws LiterLlmException Returns [`LiterLlmError::BadRequest`] if `json` is not valid JSON or
     * contains unknown fields.
     */
    pub fn create_client_from_json(json: String) -> PhpResult<DefaultClient> {
        let result = liter_llm::create_client_from_json(&json)
            .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
        Ok(DefaultClient {
            inner: Arc::new(result),
        })
    }
}

